#[test]
fn test_render_tab_preserves_highlight() {
    use crate::buffer::OptimizedBuffer;

    let mut buffer = TextBuffer::new();
    buffer.set_text("Hello\tWorld");
    buffer.add_highlight(0..11, Style::bold(), 1);

    eprintln!("[TEST] Text: {:?}", buffer.to_string());
    eprintln!("[TEST] Highlight: 0..11 (entire text including tab)");

    let view = TextBufferView::new(&buffer).viewport(0, 0, 40, 1);
    let mut output = OptimizedBuffer::new(40, 1);
    view.render_to(&mut output, 0, 0);

    // Log each cell
    for x in 0..20 {
        if let Some(cell) = output.get(x, 0) {
            let ch = cell.content.grapheme.as_deref().unwrap_or(" ");
            let is_bold = cell.style.attrs.bold;
            eprintln!("[TEST] Cell[{}]: {:?} bold={}", x, ch, is_bold);
        }
    }

    // Verify "Hello" cells (0-4) are bold
    for x in 0..5 {
        let cell = output.get(x, 0).expect("Cell should exist");
        assert!(cell.style.attrs.bold, "Cell {} 'Hello' should be bold", x);
    }

    // Verify tab spaces (cells 5-7 assuming tab_width=4) are also bold
    for x in 5..8 {
        let cell = output.get(x, 0).expect("Tab cell should exist");
        assert!(cell.style.attrs.bold, 
            "Tab cell {} should be bold (preserving highlight), style={:?}", 
            x, cell.style);
    }

    // Verify "World" cells are bold
    for x in 8..13 {
        if let Some(cell) = output.get(x, 0) {
            assert!(cell.style.attrs.bold, "Cell {} 'World' should be bold", x);
        }
    }

    eprintln!("[TEST] PASS: Tab characters preserve highlight style");
}

