/// Run this test in a real terminal to verify mouse handling.
/// Usage: cargo test --test mouse_interactive -- --nocapture --ignored
#[test]
#[ignore]
fn test_mouse_interactive() {
    use opentui::*;
    use std::io::{stdin, stdout, Read, Write};

    // Enable SGR mouse mode
    print!("\x1b[?1000h\x1b[?1006h");
    stdout().flush().unwrap();

    eprintln!("[E2E] Mouse mode enabled");
    eprintln!("[E2E] Click anywhere, scroll, drag. Press 'q' to quit.");
    eprintln!("[E2E] Testing: left/right/middle click, scroll, drag, modifiers\n");

    let mut parser = InputParser::new();
    let mut buf = [0u8; 64];
    let mut event_count = 0u32;

    let stdin = stdin();
    let mut stdin_handle = stdin.lock();

    loop {
        let n = stdin_handle.read(&mut buf).unwrap();
        let raw = &buf[..n];

        eprintln!("[E2E] Raw input ({} bytes): {:02x?}", n, raw);

        match parser.parse(raw) {
            Ok((event, _)) => {
                event_count += 1;
                match event {
                    Event::Key(key) if key.code == KeyCode::Char('q') => {
                        print!("\x1b[?1006l\x1b[?1000l");
                        stdout().flush().unwrap();
                        eprintln!("\n[E2E] Test complete. {} events captured.", event_count);
                        return;
                    }
                    Event::Mouse(mouse) => {
                        eprintln!("[E2E] #{}: Mouse {:?} {:?} at ({}, {}) mods=[shift={}, ctrl={}, alt={}]",
                            event_count, mouse.kind, mouse.button, 
                            mouse.x, mouse.y, mouse.shift, mouse.ctrl, mouse.alt);
                    }
                    other => {
                        eprintln!("[E2E] #{}: {:?}", event_count, other);
                    }
                }
            }
            Err(e) => {
                eprintln!("[E2E] Parse error: {:?}", e);
            }
        }
    }
}
